package com.example.myapp

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.util.Log
import androidx.appcompat.app.AppCompatActivity

class DeepLinkHandlerActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        // This activity doesn't have a UI, so we don't set a content view.

        handleIntent(intent)
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        handleIntent(intent)
    }

    private fun handleIntent(intent: Intent?) {
        val appLinkData: Uri? = intent?.data
        Log.d(TAG, "Deep link received: $appLinkData")

        if (appLinkData == null) {
            Log.w(TAG, "No deep link data found in intent. Navigating to Main.")
            navigateToMain()
            finish()
            return
        }

        val host = appLinkData.host
        val pathSegments = appLinkData.pathSegments

        when (host) {
            "profile" -> {
                val profileId = pathSegments.getOrNull(0)?.toIntOrNull()
                if (profileId != null) {
                    navigateToProfile(profileId)
                } else {
                    Log.e(TAG, "Invalid profile ID in deep link: $appLinkData")
                    navigateToMain()
                }
            }
            "payment" -> {
                val action = pathSegments.getOrNull(0)
                if (action == "confirm") {
                    navigateToPaymentConfirmation()
                } else {
                    Log.e(TAG, "Unsupported payment action: $action in $appLinkData")
                    navigateToMain()
                }
            }
            // Add more cases for other hosts (e.g., "settings", "product")
            else -> {
                Log.w(TAG, "Unsupported deep link host: $host. Navigating to Main.")
                navigateToMain()
            }
        }
        finish() // Crucial: finish this activity so it doesn't stay in the back stack
    }

    private fun navigateToProfile(profileId: Int) {
        val intent = Intent(this, ProfileActivity::class.java).apply {
            putExtra(ProfileActivity.EXTRA_PROFILE_ID, profileId)
            // Optional: If you want to clear the back stack before launching, use these flags
            // flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        }
        startActivity(intent)
    }

    private fun navigateToPaymentConfirmation() {
        val intent = Intent(this, PaymentConfirmationActivity::class.java).apply {
            // Optional: You might pass some data for payment, e.g., from query parameters
            // val orderId = appLinkData.getQueryParameter("orderId")
            // putExtra(PaymentConfirmationActivity.EXTRA_ORDER_ID, orderId)
        }
        startActivity(intent)
    }

    private fun navigateToMain() {
        val intent = Intent(this, MainActivity::class.java).apply {
            // If MainActivity is always the entry point when deep link fails or is generic
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        }
        startActivity(intent)
    }

    companion object {
        private const val TAG = "DeepLinkHandlerActivity"
    }
