ProfileActivity.kt

package com.example.myapp

import android.os.Bundle
import android.widget.TextView
import androidx.appcompat.app.AppCompatActivity

class ProfileActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_profile) // You'll need to create this layout

        val profileId = intent.getIntExtra(EXTRA_PROFILE_ID, -1)
        val profileIdTextView: TextView = findViewById(R.id.profile_id_text_view) // Assuming you have this TextView

        if (profileId != -1) {
            profileIdTextView.text = "Profile ID: $profileId"
        } else {
            profileIdTextView.text = "Error: Profile ID not found."
        }
    }

    companion object {
        const val EXTRA_PROFILE_ID = "extra_profile_id"
    }
}

